171	static uint64_t read_reg64(struct qemu_plugin_register *h)
172	{
173	    if (!h) return 0;
174	    g_autoptr(GByteArray) buf = g_byte_array_new();
175	    int sz = qemu_plugin_read_register(h, buf);
176	    if (sz <= 0) return 0;
177	    uint64_t v = 0;
178	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
179	    return v;
180	}
