182	// Reads up to `dst_max` bytes from a register handle. Returns the byte
183	// count written (0 on failure or NULL handle). Used for vector regs whose
184	// width = vlenb bytes.
185	static size_t read_reg_bytes(struct qemu_plugin_register *h,
186	                             uint8_t *dst, size_t dst_max)
187	{
188	    if (!h || dst_max == 0) return 0;
189	    g_autoptr(GByteArray) buf = g_byte_array_new();
190	    int sz = qemu_plugin_read_register(h, buf);
191	    if (sz <= 0) return 0;
192	    size_t n = (size_t) sz < dst_max ? (size_t) sz : dst_max;
193	    memcpy(dst, buf->data, n);
194	    return n;
195	}
