22	template<typename Trigger>
23	class HandoffController
24	{
25	public:
26	  HandoffController(Trigger trigger, DmiBus& bus)
27	      : trigger_{std::move(trigger)}, drain_{bus}
28	  {}
29	
30	  // Snapshot of the QEMU 1 input state. When set, drain merges FP/CSR/V
31	  // fields from the snapshot into the freshly drained GPRs+PC, avoiding
32	  // a per-field DM Abstract Command on every handoff.
33	  void set_passthrough_input(hybrid_state_v1 input)
34	  {
35	    passthrough_ = input;
36	  }
37	
38	  template<typename GprProbe>
39	  auto on_retire(uint64_t pc, GprProbe&& read_gpr)
40	    -> std::optional<hybrid_state_v1>
41	  {
42	    if constexpr (requires { trigger_.observe_commit(); }) {
43	      trigger_.observe_commit();
44	    }
45	    const auto hit = trigger_.lookup(pc);
46	    if (!hit) return std::nullopt;
47	
48	    bool fire = false;
49	    switch (hit->kind) {
50	    case HYBRID_HANDOFF_EXIT:
51	      fire = true;
52	      break;
53	    case HYBRID_HANDOFF_RUNTIME: {
54	      const auto rs1 = decode_csrrw_rs1(hit->insn);
55	      fire = (read_gpr(rs1) == 1u);
56	      break;
57	    }
58	    case HYBRID_HANDOFF_ENTER:  // entry is QEMU's job; vsim ignores it
59	    case HYBRID_HANDOFF_NONE:
60	      break;
61	    }
62	    if (!fire) return std::nullopt;
63	    if (passthrough_) return drain_.drain_with_passthrough(*passthrough_);
64	    return drain_.drain();
65	  }
66	
67	private:
68	  Trigger trigger_;
69	  StateDrain drain_;
70	  std::optional<hybrid_state_v1> passthrough_;
71	};
