23	struct CsrTriggerHit
24	{
25	  hybrid_handoff_kind kind;
26	  uint32_t insn;
27	};
28	
29	inline auto decode_csrrw_rs1(uint32_t insn) -> uint8_t
30	{
31	  return static_cast<uint8_t>((insn >> 15) & 0x1Fu);
32	}
33	
34	class CsrTrigger
35	{
36	public:
37	  void scan_buffer(std::span<const uint8_t> code, uint64_t base_pc)
38	  {
39	    std::size_t i = 0;
40	    while (i + sizeof(uint16_t) <= code.size()) {
41	      uint16_t lo = 0;
42	      std::memcpy(&lo, code.data() + i, sizeof(lo));
43	
44	      const bool is_32 = (lo & 0x3u) == 0x3u;
45	      if (is_32) {
46	        if (i + sizeof(uint32_t) > code.size()) break;
47	        uint32_t insn = 0;
48	        std::memcpy(&insn, code.data() + i, sizeof(insn));
49	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
50	        if (hybrid_match_handoff_insn(insn, &kind)) {
51	          hits_.insert_or_assign(base_pc + i, CsrTriggerHit{kind, insn});
52	        }
53	        i += sizeof(uint32_t);
54	      } else {
55	        i += sizeof(uint16_t);
56	      }
57	    }
58	  }
59	
60	  // PC-trigger mode: insert a synthetic hit without scanning. Used when the
61	  // orchestrator passes --hybrid-exit-pc on the CLI; in that case the binary
62	  // need not contain a magic csrwi, and `insn` is unused (HandoffController
63	  // decodes the insn only on the RUNTIME arm; PC mode only inserts EXIT).
64	  void add_pc_hit(uint64_t pc, hybrid_handoff_kind kind)
65	  {
66	    hits_.insert_or_assign(pc, CsrTriggerHit{kind, /*insn=*/0u});
67	  }
68	
69	  auto lookup(uint64_t pc) const -> std::optional<CsrTriggerHit>
70	  {
71	    if (auto it = hits_.find(pc); it != hits_.end()) return it->second;
72	    return std::nullopt;
73	  }
74	
75	  auto empty() const -> bool { return hits_.empty(); }
76	
77	private:
78	  std::unordered_map<uint64_t, CsrTriggerHit> hits_;
79	};
